// Input Validation & Normalization
// Validates input schema, generates sales_id, adds timestamp, normalizes fields

// Get input data
const items = $input.all();

if (items.length === 0) {
  throw new Error('No input data received');
}

const inputData = items[0].json;
const payload = inputData.payload || {};

// Check if payload is null or empty - provide helpful error with context
if (!inputData.payload || typeof inputData.payload !== 'object' || Object.keys(inputData.payload).length === 0) {
  // For testing/debugging: Create a sample payload structure
  const samplePayload = {
    company_name: 'Sample Company',
    contact_email: 'contact@example.com',
    contact_name: 'John Doe',
    lead_source: 'website',
    deal_size_estimate: 15000,
    industry: 'Retail',
    company_size: '50-100',
    notes: 'Sample lead for testing'
  };

  // Generate sales_id using native JavaScript
  const sales_id = 'SALE-' + Date.now() + '-' + Math.random().toString(36).substring(2, 15);
  const timestamp = new Date().toISOString();

  // Return sample data with warning
  return [{ 
    json: {
      ...inputData,
      sales_id: sales_id,
      timestamp: timestamp,
      company_name: samplePayload.company_name,
      contact_email: samplePayload.contact_email,
      contact_name: samplePayload.contact_name,
      lead_source: samplePayload.lead_source,
      deal_size_estimate: samplePayload.deal_size_estimate,
      industry: samplePayload.industry,
      company_size: samplePayload.company_size,
      notes: samplePayload.notes + ' [WARNING: Using sample data - payload was null/empty]',
      pricing_change: false,
      contract_required: false,
      _warning: 'Payload was null or empty - using sample data for testing'
    }
  }];
}

// Required fields validation
const requiredFields = ['company_name', 'contact_email', 'lead_source', 'deal_size_estimate'];
const missingFields = requiredFields.filter(field => !payload[field]);

if (missingFields.length > 0) {
  throw new Error('Missing required fields in payload: ' + missingFields.join(', ') + '. Required fields are: ' + requiredFields.join(', '));
}

// Generate sales_id using native JavaScript (no external dependencies)
const sales_id = 'SALE-' + Date.now() + '-' + Math.random().toString(36).substring(2, 15);

// Add timestamp
const timestamp = new Date().toISOString();

// Build validated data object with all required fields
const validatedData = {
  ...inputData,
  sales_id: sales_id,
  timestamp: timestamp,
  company_name: payload.company_name,
  contact_email: payload.contact_email,
  contact_name: payload.contact_name || '',
  lead_source: (payload.lead_source || '').toString().toLowerCase().trim(),
  deal_size_estimate: parseFloat(payload.deal_size_estimate),
  industry: payload.industry || '',
  company_size: payload.company_size || '',
  notes: payload.notes || '',
  pricing_change: false,
  contract_required: false
};

// Return validated data
return [{ json: validatedData }];

// Cold Lead Auto-Nurture - Generate nurture email and mark as nurtured

const items = $input.all();
const results = [];

for (const item of items) {
  const leadData = item.json;

  // Extract lead information
  const salesId = leadData.sales_id || leadData.id || 'UNKNOWN';
  const companyName = leadData.company_name || leadData.company || 'Valued Customer';
  const contactName = leadData.contact_name || leadData.name || 'there';
  const email = leadData.email || leadData.contact_email || '';
  const leadType = leadData.lead_type || 'cold';
  const reason = leadData.qualification_reason || 'does not meet current qualification criteria';

  // Generate personalized nurture email
  const nurtureEmail = {
    to: email,
    subject: `Stay Connected - ${companyName}`,
    body: `Hi ${contactName},\n\nThank you for your interest in our services. While we understand that now may not be the right time for ${companyName} to move forward, we'd love to stay connected.\n\nWe'll be sharing valuable insights, industry updates, and special offers over the coming months that might be helpful for your business.\n\nReason for nurture track: ${reason}\n\nFeel free to reach out anytime if your needs change or if you'd like to discuss how we can support your goals.\n\nBest regards,\nSales Team`,
    type: 'nurture_sequence'
  };

  // Create structured response
  const response = {
    sales_id: salesId,
    status: 'simulation_only',
    deal_status: 'not_committed',
    decision_summary: 'Cold lead - auto-nurture sequence initiated',
    lead_type: leadType,
    deal_value: 0,
    nurture_action: {
      action_type: 'email_nurture_sequence',
      email_generated: nurtureEmail,
      next_followup_days: 30,
      nurture_track: 'cold_lead_warming',
      timestamp: new Date().toISOString()
    },
    company_name: companyName,
    contact_name: contactName,
    contact_email: email,
    qualification_reason: reason,
    workflow_stage: 'auto_nurture_complete'
  };

  results.push(response);
}

return results.map(result => ({ json: result }));

