// Handle CSO rejection or revision request
const items = $input.all();
const results = [];

for (const item of items) {
  const csoDecision = item.json.cso_decision || item.json.decision;
  const leadData = item.json;

  if (csoDecision === 'rejected') {
    // Handle outright rejection - mark as lost
    results.push({
      json: {
        ...leadData,
        status: 'rejected',
        deal_status: 'not_committed',
        lost_reason: 'CSO rejected the deal',
        cso_rejection_reason: leadData.rejection_reason || 'Deal does not meet approval criteria',
        decision_summary: leadData.cso_notes || leadData.rejection_reason || 'Deal does not meet approval criteria',
        final_decision: 'rejected',
        timestamp: new Date().toISOString(),
        workflow_stage: 'cso_rejection_handled'
      }
    });
  } else if (csoDecision === 'revision_required') {
    // Handle revision request - loop back to pricing with changes
    results.push({
      json: {
        ...leadData,
        status: 'revision_in_progress',
        deal_status: 'not_committed',
        revision_requested: true,
        required_changes: leadData.required_changes || [],
        cso_feedback: leadData.feedback || 'Revisions required before approval',
        decision_summary: leadData.cso_notes || 'Revisions required before approval',
        revision_count: (leadData.revision_count || 0) + 1,
        timestamp: new Date().toISOString(),
        workflow_stage: 'returning_to_pricing',
        // Pass back to pricing agent for adjustments
        loop_back_to_pricing: true
      }
    });
  } else {
    // Unexpected decision state
    results.push({
      json: {
        ...leadData,
        status: 'error',
        deal_status: 'not_committed',
        error_message: `Unexpected CSO decision: ${csoDecision}`,
        decision_summary: `Unexpected CSO decision: ${csoDecision}`,
        timestamp: new Date().toISOString(),
        workflow_stage: 'rejection_handler_error'
      }
    });
  }
}

return results;

