// Simulation Mode Response - No CRM Mutation
// Return deal details with simulation flag

const items = $input.all();
const results = [];

for (const item of items) {
  const dealData = item.json;

  results.push({
    json: {
      status: 'simulation_only',
      deal_status: 'not_committed',
      decision_summary: 'Simulation mode – NO SALES COMMITMENT',
      mode: 'simulation',
      note: 'NON-EXECUTABLE – FOR REVIEW ONLY',
      deal_details: {
        lead_id: dealData.lead_id || dealData.leadId,
        company_name: dealData.company_name || dealData.companyName,
        contact_name: dealData.contact_name || dealData.contactName,
        qualification_score: dealData.qualification_score || dealData.qualificationScore,
        pricing_strategy: dealData.pricing_strategy || dealData.pricingStrategy,
        proposed_price: dealData.proposed_price || dealData.proposedPrice,
        discount_percentage: dealData.discount_percentage || dealData.discountPercentage,
        cso_approval: dealData.cso_approval || dealData.csoApproval,
        sales_rep_notes: dealData.sales_rep_notes || dealData.salesRepNotes,
        deal_stage: 'negotiating',
        timestamp: new Date().toISOString()
      },
      message: 'Deal is in negotiation phase. Mode is set to simulation - no changes have been made to the CRM.'
    }
  });
}

return results;

// CRM Update with Idempotent Logic
// Updates lead status to 'completed' and sets deal details

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // Extract sales_id from previous agent output
  const salesId = data.sales_id || data.lead_id || `SALE-${Date.now()}`;
  const recommendedPrice = data.recommended_price || data.final_price || data.deal_value || 0;

  // Calculate expected close date (30 days from now)
  const expectedCloseDate = new Date();
  expectedCloseDate.setDate(expectedCloseDate.getDate() + 30);

  // Build decision summary from available data
  const decisionSummary = {
    lead_qualification: data.lead_type || data.qualification_score || 'N/A',
    pricing_decision: data.pricing_rationale || data.recommended_price || 'N/A',
    cso_approval: data.cso_notes || data.decision || 'approved',
    sales_execution: data.proposal_summary || data.outreach_email || 'N/A'
  };

  // Idempotent CRM update logic
  // In a real implementation, this would check if sales_id exists in CRM
  // For now, we'll create/update the record

  const crmRecord = {
    sales_id: salesId,
    lead_id: data.lead_id || data.company_name,
    company_name: data.company_name,
    status: 'completed',
    deal_status: 'committed',
    lead_status: 'won',
    deal_value: recommendedPrice,
    expected_close_date: expectedCloseDate.toISOString().split('T')[0],
    updated_at: new Date().toISOString(),
    sales_rep: data.sales_rep || 'AI Sales Agent',
    pricing_strategy: data.pricing_strategy || 'standard',
    discount_applied: data.discount_percentage || 0,
    decision_summary: decisionSummary,

    // Preserve original data
    original_data: {
      company_size: data.company_size,
      industry: data.industry,
      budget: data.budget,
      timeline: data.timeline,
      qualification_score: data.qualification_score
    },

    // Preserve all audit metadata
    audit_metadata: {
      crm_operation: 'upsert',
      idempotency_key: salesId,
      processed_by: 'n8n-sales-workflow',
      workflow_id: $workflow.id,
      workflow_name: $workflow.name,
      execution_id: $execution.id,
      timestamp: new Date().toISOString(),
      lead_score: data.lead_score,
      lead_type: data.lead_type,
      cso_approved: data.cso_approved || true,
      pricing_rationale: data.pricing_rationale,
      cso_notes: data.cso_notes
    }
  };

  results.push({
    json: crmRecord
  });
}

return results;

// Log All Operations - Comprehensive Workflow Logging
// Captures ALL execution paths: lead scoring, pricing decisions, CSO approvals, CRM updates, finance notifications,
// confidence gates, founder approvals, CREA blocks, and execution metadata

const items = $input.all();
const timestamp = new Date().toISOString();
const workflowId = $workflow.id;
const workflowName = $workflow.name;
const executionId = $execution.id;

// Initialize comprehensive log entry
const logEntry = {
  timestamp,
  workflow: {
    id: workflowId,
    name: workflowName,
    executionId
  },
  operations: [],
  summary: {
    totalItems: items.length,
    leadScores: [],
    pricingDecisions: [],
    csoApprovals: [],
    crmUpdates: [],
    financeNotifications: [],
    confidenceGates: [],
    founderApprovals: [],
    creaBlocks: [],
    contractValidations: [],
    dealCommitments: [],
    executionPaths: []
  },
  decisionPoints: {
    coldLeadNurtures: 0,
    csoRejections: 0,
    csoRevisionsRequired: 0,
    lowConfidencePaused: 0,
    creaBlocked: 0,
    founderApprovalRequired: 0,
    founderApprovalGranted: 0,
    simulationMode: 0,
    executionMode: 0,
    hotLeads: 0,
    warmLeads: 0
  }
};

// Process each item and extract ALL relevant data
for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  const operation = {
    itemIndex: i,

    // Core workflow data
    leadScore: item.lead_score || item.leadScore || null,
    leadType: item.lead_type || item.leadType || null,
    pricingDecision: item.pricing_decision || item.pricingDecision || null,
    csoApproval: item.cso_approval || item.csoApproval || null,
    csoDecision: item.cso_decision || item.decision || null,
    crmUpdate: item.crm_update || item.crmUpdate || null,
    financeNotification: item.finance_notification || item.financeNotification || null,

    // New tracking fields
    confidenceScore: item.confidence_score || item.confidenceScore || null,
    confidenceGatePassed: item.confidence_gate_passed || item.confidenceGatePassed || null,
    founderApprovalRequired: item.founder_approval_required || item.founderApprovalRequired || null,
    founderApprovalStatus: item.founder_approval_status || item.founderApprovalStatus || null,
    creaBlocked: item.crea_blocked || item.creaBlocked || null,
    creaBlockReason: item.crea_block_reason || item.creaBlockReason || null,
    contractValid: item.contract_valid || item.contractValid || null,
    dealCommitted: item.deal_committed || item.dealCommitted || null,
    executionMode: item.mode || null,
    status: item.status || null,
    workflowStage: item.workflow_stage || item.workflowStage || null,

    // Execution path tracking
    executionPath: item.execution_path || item.executionPath || 'unknown',

    rawData: item
  };

  logEntry.operations.push(operation);

  // Aggregate summary data
  if (operation.leadScore) {
    logEntry.summary.leadScores.push(operation.leadScore);
  }
  if (operation.pricingDecision) {
    logEntry.summary.pricingDecisions.push(operation.pricingDecision);
  }
  if (operation.csoApproval) {
    logEntry.summary.csoApprovals.push(operation.csoApproval);
  }
  if (operation.crmUpdate) {
    logEntry.summary.crmUpdates.push(operation.crmUpdate);
  }
  if (operation.financeNotification) {
    logEntry.summary.financeNotifications.push(operation.financeNotification);
  }
  if (operation.confidenceScore !== null) {
    logEntry.summary.confidenceGates.push({
      score: operation.confidenceScore,
      passed: operation.confidenceGatePassed
    });
  }
  if (operation.founderApprovalRequired !== null) {
    logEntry.summary.founderApprovals.push({
      required: operation.founderApprovalRequired,
      status: operation.founderApprovalStatus
    });
  }
  if (operation.creaBlocked) {
    logEntry.summary.creaBlocks.push({
      blocked: operation.creaBlocked,
      reason: operation.creaBlockReason
    });
  }
  if (operation.contractValid !== null) {
    logEntry.summary.contractValidations.push(operation.contractValid);
  }
  if (operation.dealCommitted !== null) {
    logEntry.summary.dealCommitments.push(operation.dealCommitted);
  }
  if (operation.executionPath) {
    logEntry.summary.executionPaths.push(operation.executionPath);
  }

  // Track decision points
  if (operation.leadType === 'cold') {
    logEntry.decisionPoints.coldLeadNurtures++;
  }
  if (operation.leadType === 'hot') {
    logEntry.decisionPoints.hotLeads++;
  }
  if (operation.leadType === 'warm') {
    logEntry.decisionPoints.warmLeads++;
  }
  if (operation.csoDecision === 'rejected') {
    logEntry.decisionPoints.csoRejections++;
  }
  if (operation.csoDecision === 'revision_required') {
    logEntry.decisionPoints.csoRevisionsRequired++;
  }
  if (operation.status === 'low_confidence_paused') {
    logEntry.decisionPoints.lowConfidencePaused++;
  }
  if (operation.creaBlocked === true) {
    logEntry.decisionPoints.creaBlocked++;
  }
  if (operation.founderApprovalRequired === true) {
    logEntry.decisionPoints.founderApprovalRequired++;
  }
  if (operation.founderApprovalStatus === 'approved') {
    logEntry.decisionPoints.founderApprovalGranted++;
  }
  if (operation.executionMode === 'simulation') {
    logEntry.decisionPoints.simulationMode++;
  }
  if (operation.executionMode === 'execute') {
    logEntry.decisionPoints.executionMode++;
  }
}

// Console logging with structured output
console.log('='.repeat(80));
console.log('COMPREHENSIVE WORKFLOW EXECUTION LOG');
console.log('='.repeat(80));
console.log(`Timestamp: ${timestamp}`);
console.log(`Workflow: ${workflowName} (${workflowId})`);
console.log(`Execution ID: ${executionId}`);
console.log(`Total Items Processed: ${items.length}`);
console.log('-'.repeat(80));

// Log summary statistics
console.log('\nCORE OPERATIONS SUMMARY:');
console.log(`  Lead Scores: ${logEntry.summary.leadScores.length}`);
console.log(`  Pricing Decisions: ${logEntry.summary.pricingDecisions.length}`);
console.log(`  CSO Approvals: ${logEntry.summary.csoApprovals.length}`);
console.log(`  CRM Updates: ${logEntry.summary.crmUpdates.length}`);
console.log(`  Finance Notifications: ${logEntry.summary.financeNotifications.length}`);

console.log('\nGATES & CONTROLS SUMMARY:');
console.log(`  Confidence Gates: ${logEntry.summary.confidenceGates.length}`);
console.log(`  Founder Approvals: ${logEntry.summary.founderApprovals.length}`);
console.log(`  CREA Blocks: ${logEntry.summary.creaBlocks.length}`);
console.log(`  Contract Validations: ${logEntry.summary.contractValidations.length}`);
console.log(`  Deal Commitments: ${logEntry.summary.dealCommitments.length}`);

console.log('\nDECISION POINTS:');
console.log(`  Cold Lead Nurtures: ${logEntry.decisionPoints.coldLeadNurtures}`);
console.log(`  Hot Leads: ${logEntry.decisionPoints.hotLeads}`);
console.log(`  Warm Leads: ${logEntry.decisionPoints.warmLeads}`);
console.log(`  CSO Rejections: ${logEntry.decisionPoints.csoRejections}`);
console.log(`  CSO Revisions Required: ${logEntry.decisionPoints.csoRevisionsRequired}`);
console.log(`  Low Confidence Paused: ${logEntry.decisionPoints.lowConfidencePaused}`);
console.log(`  CREA Blocked: ${logEntry.decisionPoints.creaBlocked}`);
console.log(`  Founder Approval Required: ${logEntry.decisionPoints.founderApprovalRequired}`);
console.log(`  Founder Approval Granted: ${logEntry.decisionPoints.founderApprovalGranted}`);
console.log(`  Simulation Mode: ${logEntry.decisionPoints.simulationMode}`);
console.log(`  Execution Mode: ${logEntry.decisionPoints.executionMode}`);

console.log('\nEXECUTION PATHS:');
const pathCounts = {};
logEntry.summary.executionPaths.forEach(path => {
  pathCounts[path] = (pathCounts[path] || 0) + 1;
});
Object.entries(pathCounts).forEach(([path, count]) => {
  console.log(`  ${path}: ${count}`);
});

// Log detailed operations
console.log('\nDETAILED OPERATIONS:');
logEntry.operations.forEach((op, idx) => {
  console.log(`\n  Item ${idx}:`);
  console.log(`    Execution Path: ${op.executionPath}`);
  console.log(`    Workflow Stage: ${op.workflowStage || 'N/A'}`);
  console.log(`    Status: ${op.status || 'N/A'}`);
  if (op.leadScore) console.log(`    Lead Score: ${JSON.stringify(op.leadScore)}`);
  if (op.leadType) console.log(`    Lead Type: ${op.leadType}`);
  if (op.pricingDecision) console.log(`    Pricing Decision: ${JSON.stringify(op.pricingDecision)}`);
  if (op.csoApproval !== null) console.log(`    CSO Approval: ${op.csoApproval}`);
  if (op.csoDecision) console.log(`    CSO Decision: ${op.csoDecision}`);
  if (op.confidenceScore !== null) console.log(`    Confidence Score: ${op.confidenceScore} (Passed: ${op.confidenceGatePassed})`);
  if (op.founderApprovalRequired !== null) console.log(`    Founder Approval Required: ${op.founderApprovalRequired} (Status: ${op.founderApprovalStatus || 'pending'})`);
  if (op.creaBlocked) console.log(`    CREA Blocked: ${op.creaBlocked} (Reason: ${op.creaBlockReason})`);
  if (op.contractValid !== null) console.log(`    Contract Valid: ${op.contractValid}`);
  if (op.dealCommitted !== null) console.log(`    Deal Committed: ${op.dealCommitted}`);
  if (op.executionMode) console.log(`    Execution Mode: ${op.executionMode}`);
  if (op.crmUpdate) console.log(`    CRM Update: ${JSON.stringify(op.crmUpdate)}`);
  if (op.financeNotification) console.log(`    Finance Notification: ${JSON.stringify(op.financeNotification)}`);
});

console.log('\n' + '='.repeat(80));

// Return the comprehensive log entry for downstream processing
return [{ json: logEntry }];

